import{c as e,Q as t,j as n,m as r}from"./chunks/framework.DpF7k2f3.js";const u=JSON.parse('{"title":"Chapter 10: LlamaIndex & Vector Databases","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/part3-practice/chapter10.md","filePath":"en/part3-practice/chapter10.md"}'),o={name:"en/part3-practice/chapter10.md"};function i(s,a,l,c,p,h){return t(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="chapter-10-llamaindex-vector-databases" tabindex="-1">Chapter 10: LlamaIndex &amp; Vector Databases <a class="header-anchor" href="#chapter-10-llamaindex-vector-databases" aria-label="Permalink to &quot;Chapter 10: LlamaIndex &amp; Vector Databases&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>In the previous chapter, we learned LangChain. It&#39;s good at <strong>connecting various components</strong>—building Agents, calling tools, orchestrating complex flows.</p><p>But have you noticed a problem: although LangChain can do RAG, it&#39;s actually quite weak in <strong>data processing and indexing</strong>. How to chunk documents, how to store efficiently, how to retrieve precisely—LangChain struggles with these dirty, exhausting tasks.</p><p>This is LlamaIndex&#39;s specialty.</p><p>If LangChain is the &quot;process orchestration master,&quot; then LlamaIndex is the &quot;data indexing expert.&quot; Its core philosophy: <strong>making your private data efficiently queryable by LLMs.</strong></p><p>After reading this chapter, you will take away:</p><ul><li>LlamaIndex core architecture and design philosophy (division of labor with LangChain)</li><li><strong>Advanced index types</strong>: Summary Index, Keyword Table Index, Knowledge Graph Index</li><li><strong>LlamaIndex + LangChain collaboration</strong>: Boundary of respective advantages and hybrid architecture</li><li>Vector database selection: Chroma / Qdrant / Milvus / Pinecone and their applicable scenarios</li><li><strong>Self-built vs cloud service</strong> cost and operations comparison</li><li><strong>Vector database performance optimization</strong>: HNSW parameter tuning, quantization, sharding</li></ul><hr><blockquote><p><strong>Full translation coming soon. You can read the Chinese version in the meantime.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter10.html">阅读中文版</a></p></blockquote>',10)])])}const g=e(o,[["render",i]]);export{u as __pageData,g as default};
